import { TOAST_TRIGGER } from '@/models/events';
import { ToastError } from '@/models/toast';
import { User } from '@/models/user';
import posthog from 'posthog-js';
import { url } from './api.service';

export const getAuthenticatedUser = async (): Promise<User> => {
    console.log('auth@getAuthenticatedUser');

    const r = await fetch(url('/isiWeb/web/v1/global-data'), {
        credentials: 'include',
        headers: {
            'Content-Type': 'application/json',
            Accept: 'application/json',
        },
    });

    if (r.status !== 200 && !location.pathname.includes('/login')) {
        window.PineconeRouter.context.redirect('/login');
    }

    if (r.status === 200 && location.pathname.includes('/login')) {
        window.PineconeRouter.context.redirect('/');
    }

    const response = await r.json();
    const user: User = response.data as User;

    sessionStorage.setItem('isiparts.user', JSON.stringify(user));

    if (undefined !== user) {
        posthog.identify(user.usuario, { user });
    }

    return user;
};

export const authenticate = async (username: string, password: string): Promise<void> => {
    console.log('auth@authenticate');

    try {
        const body = new URLSearchParams();
        body.set('j_username', username);
        body.set('j_password', password);

        const r = await fetch(url('/isiWeb/static/auth/j_spring_security_check'), {
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded',
            },
            body,
            credentials: 'include',
        });

        if (!r.ok) {
            throw new Error('Authentication failed');
        }

        // JSESSIONID is now set
    } catch (error) {
        console.warn('Posthog identify failed', error);

        window.dispatchEvent(
            new CustomEvent(TOAST_TRIGGER, {
                detail: {
                    msg: error,
                    level: ToastError,
                },
            }),
        );
    }
};

export const logout = async () => {
    console.log('auth@logout');

    const r = await fetch(url('/isiWeb/static/auth/j_spring_security_logout'), {
        method: 'POST',
        credentials: 'include',
    });

    if (r.status !== 200) {
        throw new Error('Logout failed');
    }

    // JSESSIONID is now unset

    sessionStorage.removeItem('isiparts.user');

    window.location.href = '/login';
};
